<template>
  <el-tag round class="tag-view-item" v-for="tag in tags" v-bind:key="tag" :type="getType(tag)" effect="plain">
    {{ tag }}
  </el-tag>
</template>


<script>
const defaultType = "info";

export default {
  props: {
    tags: Array,
    useType: Boolean
  },
  methods: {
    getType: function (tag) {
      if (!this.useType) {
        return defaultType;
      }
      switch (tag) {
        case "VScript":
        case "C#":
        case "ActionScript 3":
        case "Rust":
          return "primary";

        case "Paid":
          return "warning";

        case "School":
          return "success";

        default:
          return defaultType;
      }
    }
  }
}
</script>

<style>
.tag-view-item {
  margin: 2px;
}

.tag-view-item+.tag-view-item {
  margin: 2px;
}
</style>