<template>
  <el-card class="project-view-item">
    <ref-link :text="project.name" :type="3" />
    <p v-if="project.year" class="project-view-subtitle"> {{ project.year }} </p>
    <p v-if="project.description" class="project-view-content"> {{ project.description }} </p>
    <div v-if="project.links" class="project-view-links">
      <div v-for="source in project.links" v-bind:key="source.link">
        <el-link type="primary" :href="source.url" target="_blank">
          {{ source.name }}
        </el-link>
      </div>
    </div>
    <tag-view v-if="project.tags" :tags="project.tags" :useType="true" />
  </el-card>
</template>


<script>
import TagView from '@/components/TagView.vue';
import RefLink from '@/components/RefLink.vue';
export default {
  components: {
    TagView,
    RefLink
  },
  props: {
    project: Array
  },
  methods: {
    formatRef: function (prefix, regular) {
      return prefix + regular.replace(/ /g, "_").toLowerCase();
    }
  }
}
</script>

