<template>
  <el-row>
    <el-link :class="`ref-link ref-h${type}`" :underline="false" :href="format(text, '#')" :name="format(text)">
      {{ text }}
    </el-link>
  </el-row>
</template>

<script>
export default {
  props: {
    text: String,
    type: Number
  },
  methods: {
    format: function (regular, prefix = '') {
      return prefix + regular.replace(/ /g, "_").toLowerCase();
    }
  }
}
</script>

