<template>
  <div>
    <div class="aboutme-item">
      <ref-link text="about:nupsi" :type="1" />
      <external-link-view />
    </div>

    <div class="aboutme-item">
      <ref-link text="Education" :type="2" />
      <timeline-view :items="about.education" />
    </div>

    <div class="aboutme-item">
      <ref-link text="Projects" :type="2" />
      <el-timeline class="timeline-view">
        <el-timeline-item v-for="group in projectsByYear()" :key="group.year" :timestamp="group.year" placement="top">
          <project-view v-for="project in group.projects" v-bind:key="project.name" :project="project" />
        </el-timeline-item>
      </el-timeline>
    </div>

    <div class="aboutme-item">
      <ref-link text="Programming Languages" :type="3" />
      <div>
        <tag-view :tags="about.programminglangs" :useType="false" />
      </div>
    </div>

    <div class="aboutme-item">
      <ref-link text="Web Dev" :type="3" />
      <div>
        <tag-view :tags="about.webstack" :useType="false" />
      </div>
    </div>

    <div class="aboutme-item">
      <ref-link text="Miscellanious" :type="3" />
      <div>
        <tag-view :tags="about.frameworks" :useType="false" />
      </div>
    </div>

    <div class="aboutme-item">
      <ref-link text="Operating Systems" :type="3" />
      <div>
        <tag-view :tags="about.os" :useType="false" />
      </div>
    </div>

    <div class="aboutme-item">
      <ref-link text="Programs" :type="3" />
      <div>
        <tag-view :tags="about.programs" :useType="false" />
      </div>
    </div>

    <div class="aboutme-item">
      <footer-view />
    </div>
  </div>
</template>


<script>
import ExternalLinkView from '@/views/ExternalLinkView.vue';
import FooterView from '@/views/FooterView.vue';
import TimelineView from '@/components/TimelineView.vue';
import ProjectView from '@/components/ProjectView.vue';
import RefLink from '@/components/RefLink.vue';
import TagView from '@/components/TagView.vue';
import AboutData from '@/data/pageData.json';

export default {
  components: {
    TimelineView,
    ProjectView,
    ExternalLinkView,
    FooterView,
    RefLink,
    TagView
  },
  data() {
    return { about: AboutData }
  },
  methods: {
    projectsByYear: function () {
      return this
        .about
        .projects
        .reduce((acc, cur) => {
          if (acc.length == 0) {
            return [{ year: cur.year, projects: [cur] }];
          } else {
            if (acc[acc.length - 1].year == cur.year) {
              acc[acc.length - 1].projects.push(cur);
            } else {
              acc.push({ year: cur.year, projects: [cur] })
            }
          }
          return acc;
        }, []);
    }
  }
}
</script>

<style>
.aboutme-item {
  padding: 10px;
}
</style>
